import{_ as o,o as a,c as d,ag as r}from"./chunks/framework.C6K0jwmI.js";const b=JSON.parse('{"title":"Part 2 — スタッフ管理（超詳細版）","description":"","frontmatter":{"title":"Part 2 — スタッフ管理（超詳細版）","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-19T00:00:00.000Z"},"headers":[],"relativePath":"operations/part2-staff.md","filePath":"operations/part2-staff.md"}'),e={name:"operations/part2-staff.md"};function l(i,t,s,n,h,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="part-2-—-スタッフ管理" tabindex="-1">Part 2 — スタッフ管理 <a class="header-anchor" href="#part-2-—-スタッフ管理" aria-label="Permalink to &quot;Part 2 — スタッフ管理&quot;">​</a></h1><p>このページでは、スタッフのアカウント作成・シフト管理・勤怠打刻を、<strong>指の動きを 1 つずつ</strong> 順番に説明します。</p><div class="tip custom-block"><p class="custom-block-title">POSLA の鉄則: 1 人 1 アカウント</p><p><strong>絶対に「キッチン」「ホール」のような共有アカウントを作らないでください</strong>。以下が全部壊れます。</p><ul><li>勤怠打刻（誰が出勤したか分からない）</li><li>監査ログ（誰が操作したか記録されない）</li><li>スタッフ評価レポート（全員のデータが混ざる）</li><li>シフト管理（個別割当不可）</li></ul><p>必ず <strong>スタッフ 1 人につき 1 つのアカウント</strong> を作成してください。</p></div><div class="warning custom-block"><p class="custom-block-title">個人スマホは業務に使わない</p><p>POSLA の運用前提は、ハンディ・KDS・レジは <strong>全て店舗が用意する備品端末</strong> です。スタッフ個人のスマートフォンを業務に使う BYOD 運用は推奨しません（労務・セキュリティ・紛失時補償の問題を避けるため）。ハンディ端末は店舗が複数台購入して device アカウントでログインしっぱなしで運用するのが標準です。</p></div><hr><h2 id="_2-0-作成できるアカウントの種類-4-種類" tabindex="-1">2-0. 作成できるアカウントの種類（4 種類） <a class="header-anchor" href="#_2-0-作成できるアカウントの種類-4-種類" aria-label="Permalink to &quot;2-0. 作成できるアカウントの種類（4 種類）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>役割</th><th>作成可能者</th></tr></thead><tbody><tr><td><strong>オーナー (owner)</strong></td><td>代表者・全店舗統括</td><td>通常は POSLA 運営が契約時に発行。既存 owner から追加作成も可</td></tr><tr><td><strong>マネージャー (manager)</strong></td><td>店長・店舗運営</td><td><strong>オーナーのみ作成可</strong></td></tr><tr><td><strong>スタッフ (staff)</strong></td><td>アルバイト・社員</td><td><strong>オーナーまたはマネージャーが作成可</strong></td></tr><tr><td><strong>デバイス (device)</strong></td><td>端末専用アカウント（KDS / レジ / ハンディ）</td><td><strong>オーナーまたはマネージャーが作成可</strong></td></tr></tbody></table><p>実装:</p><ul><li><code>api/owner/users.php</code> L113 — 非オーナーは <code>staff</code> のみ作成可</li><li><code>api/store/staff-management.php</code> L42 — <code>require_role(&#39;manager&#39;)</code>（manager 以上）</li></ul><hr><h2 id="_2-1-新しいスタッフのアカウントを作る" tabindex="-1">2-1. 新しいスタッフのアカウントを作る <a class="header-anchor" href="#_2-1-新しいスタッフのアカウントを作る" aria-label="Permalink to &quot;2-1. 新しいスタッフのアカウントを作る&quot;">​</a></h2><h3 id="_2-1-1-手順-マネージャーの場合" tabindex="-1">2-1-1. 手順（マネージャーの場合） <a class="header-anchor" href="#_2-1-1-手順-マネージャーの場合" aria-label="Permalink to &quot;2-1-1. 手順（マネージャーの場合）&quot;">​</a></h3><ol><li>dashboard.html にマネージャーでログイン</li><li>上部タブ <strong>【店舗設定】</strong> → サブタブ <strong>【スタッフ管理】</strong>（<code>data-tab=&quot;staff-mgmt&quot;</code>）</li><li>画面右上の <strong>【+ 追加】</strong> ボタン（<code>btn-add-staff</code>、<code>dashboard.html</code> L296）</li><li>「スタッフ追加」モーダルが開く</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td><strong>表示名</strong></td><td>—</td><td>「田中 太郎」等（後でも変更可）</td></tr><tr><td><strong>ユーザー名</strong></td><td>✅</td><td>半角英数・ハイフン・アンダースコア 3〜50 文字（例: <code>tanaka01</code>）</td></tr><tr><td><strong>メール</strong></td><td>—</td><td>任意（通知送信用）</td></tr><tr><td><strong>パスワード</strong></td><td>✅</td><td>8 文字以上 + 英字 + 数字必須</td></tr><tr><td><strong>時給</strong></td><td>—</td><td>人件費レポート用（円 / 時、1〜10000）</td></tr><tr><td><strong>ビジブルツール</strong></td><td>—</td><td>通常は空欄（staff には不要）</td></tr></tbody></table><ol start="6"><li><strong>【保存】</strong> ボタン</li><li>スタッフに <strong>ユーザー名 + パスワード</strong> を口頭またはメモで伝える</li><li>スタッフは初回ログイン後、自分で好きなパスワードに変更（推奨）</li></ol><h3 id="_2-1-2-手順-オーナーの場合、管理者レベル" tabindex="-1">2-1-2. 手順（オーナーの場合、管理者レベル） <a class="header-anchor" href="#_2-1-2-手順-オーナーの場合、管理者レベル" aria-label="Permalink to &quot;2-1-2. 手順（オーナーの場合、管理者レベル）&quot;">​</a></h3><p>オーナーは <code>owner-dashboard.html</code> からマネージャー・スタッフを作成できます（<code>api/owner/users.php</code> 経由）。</p><ol><li>オーナーで owner-dashboard にログイン</li><li>上部タブ <strong>【ユーザー管理】</strong>（<code>data-tab=&quot;users&quot;</code>、<code>owner-dashboard.html</code> L55）</li><li><strong>【+ ユーザー追加】</strong> ボタン（<code>btn-add-user</code>）</li><li>モーダル: <ul><li>表示名</li><li>ユーザー名</li><li>メール（任意）</li><li>パスワード</li><li><strong>ロール</strong>: <code>manager</code> または <code>staff</code> のどちらか選択</li><li><strong>担当店舗</strong>: 複数チェックボックス（所属店舗）</li></ul></li><li><strong>【保存】</strong></li></ol><h3 id="_2-1-3-ユーザー名の命名ルール" tabindex="-1">2-1-3. ユーザー名の命名ルール <a class="header-anchor" href="#_2-1-3-ユーザー名の命名ルール" aria-label="Permalink to &quot;2-1-3. ユーザー名の命名ルール&quot;">​</a></h3><ul><li><strong>半角英数字 + ハイフン + アンダースコア</strong> のみ</li><li><strong>3〜50 文字</strong>（実装: <code>api/store/staff-management.php</code> L109 <code>pattern &#39;/^[a-zA-Z0-9_-]{3,50}$/&#39;</code>）</li><li><strong>POSLA 全体（グローバル）で一意</strong>（S3 セキュリティ修正 #14, 2026-04-19）。同じテナント内だけでなく、他テナントとも衝突する場合は登録できない</li></ul><div class="warning custom-block"><p class="custom-block-title">2026-04-19 仕様変更（重要）</p><p>旧仕様では「テナント内で一意」でしたが、現在は <strong>POSLA 全体（テナント横断）でグローバル一意</strong> です。テナント略号や店舗名をプレフィックスに付けて運用してください（例: <code>matsunoya_tanaka01</code>, <code>momonoya_suzuki-hall</code>）。</p></div><p><strong>推奨パターン</strong>:</p><ul><li><code>&lt;テナント略号&gt;_tanaka01</code>, <code>&lt;テナント略号&gt;_suzuki-hall</code>（人間の場合、名前 + 番号 or 役割）</li><li><code>kds-shibuya-01</code>, <code>register-ginza-01</code>, <code>handy-shinjuku-02</code>（device の場合、役割 + 店舗 + 番号）</li></ul><h3 id="_2-1-4-失敗時のエラー" tabindex="-1">2-1-4. 失敗時のエラー <a class="header-anchor" href="#_2-1-4-失敗時のエラー" aria-label="Permalink to &quot;2-1-4. 失敗時のエラー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>メッセージ</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>「ユーザー名は既に使用されています」</td><td>同名アカウントあり</td><td>別のユーザー名（例: tanaka01 → tanaka02）</td></tr><tr><td>「パスワードは8文字以上で入力してください」</td><td>短い</td><td>8 文字以上にする</td></tr><tr><td>「パスワードには英字を1文字以上含めてください」</td><td>数字のみ</td><td>英字を混ぜる</td></tr><tr><td>「パスワードには数字を1文字以上含めてください」</td><td>英字のみ</td><td>数字を混ぜる</td></tr><tr><td>「ユーザー名は半角英数字・ハイフン・アンダースコア（3〜50文字）で入力してください」</td><td>形式違反</td><td>正しい形式に</td></tr><tr><td>「メールアドレスの形式が正しくありません」</td><td>メール入力ミス</td><td>正しいメール形式に（任意なので空欄 OK）</td></tr></tbody></table><hr><h2 id="_2-1-b-スタッフのレジ担当-pin-を設定する-cp1-cb1d、2026-04-19-追加" tabindex="-1">2-1-b. スタッフのレジ担当 PIN を設定する（CP1 + CB1d、2026-04-19 追加） <a class="header-anchor" href="#_2-1-b-スタッフのレジ担当-pin-を設定する-cp1-cb1d、2026-04-19-追加" aria-label="Permalink to &quot;2-1-b. スタッフのレジ担当 PIN を設定する（CP1 + CB1d、2026-04-19 追加）&quot;">​</a></h2><p>POSレジで「誰が操作したか」を特定するため、各スタッフに <strong>4〜8 桁の PIN</strong> を設定します。</p><div class="warning custom-block"><p class="custom-block-title">マネージャーも全員 PIN 設定が必須（CB1d、2026-04-19 拡張）</p><p><strong>マネージャー / オーナーであっても自分の PIN 設定が必須</strong>になりました。レジ金庫操作（レジ開け / レジ閉め / 入金 / 出金）にも PIN が要求されるため、PIN を設定していないマネージャーは開店作業ができません。</p><p>「会計用だけ」と思って未設定のままにしていたマネージャーは、<strong>今すぐ自分の PIN を設定</strong>してください。</p></div><h3 id="pin-が必要な操作の一覧-cb1d-完全網羅" tabindex="-1">PIN が必要な操作の一覧（CB1d 完全網羅） <a class="header-anchor" href="#pin-が必要な操作の一覧-cb1d-完全網羅" aria-label="Permalink to &quot;PIN が必要な操作の一覧（CB1d 完全網羅）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>PIN 必須</th></tr></thead><tbody><tr><td>会計確定（現金 / カード / QR / Terminal）</td><td>✅</td></tr><tr><td>返金処理（部分・全額）</td><td>✅</td></tr><tr><td><strong>レジ開け</strong>（CB1d 新規）</td><td><strong>✅</strong></td></tr><tr><td><strong>レジ閉め</strong>（CB1d 新規）</td><td><strong>✅</strong></td></tr><tr><td><strong>入金（Cash In）</strong>（CB1d 新規）</td><td><strong>✅</strong></td></tr><tr><td><strong>出金（Cash Out）</strong>（CB1d 新規）</td><td><strong>✅</strong></td></tr></tbody></table><h3 id="設定手順-店長向け" tabindex="-1">設定手順（店長向け） <a class="header-anchor" href="#設定手順-店長向け" aria-label="Permalink to &quot;設定手順（店長向け）&quot;">​</a></h3><ol><li>dashboard.html → 【店舗設定】 → 【スタッフ管理】</li><li>対象スタッフの <strong>【編集】</strong> ボタン</li><li>編集モーダル内の <strong>「レジ担当 PIN」</strong> 欄に 4〜8 桁の数字を入力</li><li><strong>【保存】</strong> ボタン</li><li>スタッフに PIN を口頭で伝える</li><li>スタッフは初回ログイン時に自分で別の PIN に変更推奨</li></ol><h3 id="スタッフ自身による-pin-変更" tabindex="-1">スタッフ自身による PIN 変更 <a class="header-anchor" href="#スタッフ自身による-pin-変更" aria-label="Permalink to &quot;スタッフ自身による PIN 変更&quot;">​</a></h3><ol><li>スタッフ（マネージャー含む）が管理画面にログイン</li><li>同じ手順で自分の <strong>【編集】</strong> ボタン</li><li>「レジ担当 PIN」欄に新しい PIN を入力 → <strong>【保存】</strong></li></ol><h3 id="注意事項" tabindex="-1">注意事項 <a class="header-anchor" href="#注意事項" aria-label="Permalink to &quot;注意事項&quot;">​</a></h3><ul><li>✅ <strong>退勤時は必ず退勤打刻</strong>: 退勤したスタッフの PIN は <strong>自動無効化</strong> される（不正悪用防止）</li><li>✅ <strong>マネージャーも開店前に出勤打刻が必須</strong>（出勤打刻していないと自分の PIN でレジ開けできない）</li><li>✅ 弱い PIN は登録不可（<code>1234</code>、<code>0000</code>、ゾロ目などはエラー）</li><li>✅ PIN は他人に教えない、付箋でレジに貼らない</li><li>✅ 半年〜1 年で変更推奨</li></ul><p>詳細は <a href="./../tenant/02-login.html">2 章 2.6 担当スタッフ PIN</a> / <a href="./../tenant/08-cashier.html#86-レジ開閉操作">8 章 8.6 レジ開閉操作</a> 参照。</p><hr><h2 id="_2-2-スタッフのパスワードをリセットする" tabindex="-1">2-2. スタッフのパスワードをリセットする <a class="header-anchor" href="#_2-2-スタッフのパスワードをリセットする" aria-label="Permalink to &quot;2-2. スタッフのパスワードをリセットする&quot;">​</a></h2><p>スタッフが「パスワードを忘れた」と言ってきた時。</p><h3 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>dashboard.html → 【店舗設定】 → 【スタッフ管理】</li><li>該当スタッフの行を探す</li><li><strong>【編集】</strong> ボタン</li><li>編集モーダルが開く</li><li><strong>【新しいパスワード】</strong> 欄に新しいパスワード（8 文字以上 + 英字 + 数字）を入力</li><li><strong>【保存】</strong></li><li>スタッフに新パスワードを口頭で伝える</li><li>スタッフは次回ログイン後、自分で変更してもらう</li></ol><div class="warning custom-block"><p class="custom-block-title">新パスワードを平文でメモ・メール送信しない</p><p>セキュリティリスクがあるので、口頭で伝えるのが基本。メモでも必ず破棄。メール送信時は暗号化メッセージで。</p></div><hr><h2 id="_2-3-スタッフを削除する-退職時" tabindex="-1">2-3. スタッフを削除する（退職時） <a class="header-anchor" href="#_2-3-スタッフを削除する-退職時" aria-label="Permalink to &quot;2-3. スタッフを削除する（退職時）&quot;">​</a></h2><h3 id="推奨-削除ではなく-無効化" tabindex="-1">推奨: 削除ではなく <strong>無効化</strong> <a class="header-anchor" href="#推奨-削除ではなく-無効化" aria-label="Permalink to &quot;推奨: 削除ではなく **無効化**&quot;">​</a></h3><p>監査ログの履歴を維持するため、<strong>アカウントを物理削除せず、is_active=0（無効化）</strong> を推奨します。</p><h3 id="_2-3-1-無効化の手順" tabindex="-1">2-3-1. 無効化の手順 <a class="header-anchor" href="#_2-3-1-無効化の手順" aria-label="Permalink to &quot;2-3-1. 無効化の手順&quot;">​</a></h3><ol><li>【スタッフ管理】 で該当スタッフの <strong>【編集】</strong></li><li><strong>「有効/無効」トグル</strong> を <strong>【無効】</strong> にする</li><li><strong>【保存】</strong></li><li>以降、このスタッフはログインできなくなる</li><li>過去の注文・勤怠・操作履歴はすべて保持される</li></ol><h3 id="_2-3-2-完全削除-非推奨" tabindex="-1">2-3-2. 完全削除（非推奨） <a class="header-anchor" href="#_2-3-2-完全削除-非推奨" aria-label="Permalink to &quot;2-3-2. 完全削除（非推奨）&quot;">​</a></h3><p>どうしても完全削除したい場合:</p><ol><li>編集画面で <strong>【削除】</strong> ボタン（赤）</li><li>確認ダイアログで <strong>【OK】</strong></li><li>アカウントが削除される</li></ol><div class="danger custom-block"><p class="custom-block-title">注意</p><p>完全削除すると、過去の注文・勤怠レコードの <code>user_id</code> 参照が壊れる可能性があります。税務監査・労基対応の観点から <strong>無効化を推奨</strong>。</p></div><hr><h2 id="_2-4-デバイスアカウント-kds-レジ-ハンディ端末専用-の作り方" tabindex="-1">2-4. デバイスアカウント（KDS / レジ / ハンディ端末専用）の作り方 <a class="header-anchor" href="#_2-4-デバイスアカウント-kds-レジ-ハンディ端末専用-の作り方" aria-label="Permalink to &quot;2-4. デバイスアカウント（KDS / レジ / ハンディ端末専用）の作り方&quot;">​</a></h2><p>「人」ではなく「端末」のためのアカウントです。</p><h3 id="_2-4-1-デバイスアカウントの特徴" tabindex="-1">2-4-1. デバイスアカウントの特徴 <a class="header-anchor" href="#_2-4-1-デバイスアカウントの特徴" aria-label="Permalink to &quot;2-4-1. デバイスアカウントの特徴&quot;">​</a></h3><ul><li>ログインしっぱなし前提（端末再起動時のみ再ログイン）</li><li>シフト・人件費・スタッフ評価レポートの対象外（人間ではないため）</li><li>監査ログにはちゃんと記録される（<code>role=&#39;device&#39;</code> で識別可能）</li><li>管理画面には入れない（KDS / レジ / ハンディのいずれかに直接遷移）</li></ul><h3 id="_2-4-2-作成手順" tabindex="-1">2-4-2. 作成手順 <a class="header-anchor" href="#_2-4-2-作成手順" aria-label="Permalink to &quot;2-4-2. 作成手順&quot;">​</a></h3><ol><li>dashboard.html → 【店舗設定】 → 【スタッフ管理】</li><li>画面を下にスクロール → <strong>「デバイスアカウント」セクション</strong></li><li><strong>【+ デバイス追加】</strong> ボタン（<code>btn-add-device</code>、<code>dashboard.html</code> L304）</li><li>モーダル:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td><strong>表示名</strong></td><td>✅</td><td>「厨房KDS 1番」「レジ-渋谷-01」等の人間向けの名前</td></tr><tr><td><strong>ユーザー名</strong></td><td>✅</td><td><code>kds-shibuya-01</code> 等（英数字・ハイフン、3〜50 文字）</td></tr><tr><td><strong>パスワード</strong></td><td>✅</td><td>8 文字以上 + 英字 + 数字</td></tr><tr><td><strong>用途</strong></td><td>✅</td><td>チェックボックス: KDS / POSレジ / ハンディ から <strong>少なくとも 1 つ</strong></td></tr></tbody></table><ol start="5"><li><strong>【保存】</strong></li><li>一覧に追加される</li></ol><h3 id="_2-4-3-用途の組み合わせによる遷移先" tabindex="-1">2-4-3. 用途の組み合わせによる遷移先 <a class="header-anchor" href="#_2-4-3-用途の組み合わせによる遷移先" aria-label="Permalink to &quot;2-4-3. 用途の組み合わせによる遷移先&quot;">​</a></h3><p>device がログインした後の遷移先は、<code>visible_tools</code> の設定に従います（<code>dashboard.html</code> L546-552、優先度 <code>handy</code> &gt; <code>register</code> &gt; <code>kds</code>）。</p><table tabindex="0"><thead><tr><th>visible_tools の値</th><th>ログイン後の遷移先</th></tr></thead><tbody><tr><td><code>handy</code>（のみ）</td><td><code>/handy/index.html</code></td></tr><tr><td><code>register</code>（のみ）</td><td><code>/kds/cashier.html</code></td></tr><tr><td><code>kds</code>（のみ）</td><td><code>/kds/index.html</code></td></tr><tr><td><code>handy,register</code></td><td><code>/handy/index.html</code>（handy 優先）</td></tr><tr><td><code>handy,kds</code></td><td><code>/handy/index.html</code></td></tr><tr><td><code>register,kds</code></td><td><code>/kds/cashier.html</code>（register 優先）</td></tr><tr><td><code>handy,register,kds</code></td><td><code>/handy/index.html</code>（handy 優先）</td></tr><tr><td>未設定 or <code>kds</code>（のみ）</td><td><code>/kds/index.html</code>（デフォルト）</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">1 端末 1 用途を強く推奨</p><p>複数選択は技術的に可能ですが、<strong>運用上は 1 端末 1 用途</strong>（KDS のみ / POSレジ のみ / ハンディのみ）にしてください。KDS 画面表示中に会計が来て切替えたらピックアップ画面が消える、といった事故が起きます。</p></div><h3 id="_2-4-4-ワンタイムトークンで端末を自動セットアップする-f-da1" tabindex="-1">2-4-4. ワンタイムトークンで端末を自動セットアップする（F-DA1） <a class="header-anchor" href="#_2-4-4-ワンタイムトークンで端末を自動セットアップする-f-da1" aria-label="Permalink to &quot;2-4-4. ワンタイムトークンで端末を自動セットアップする（F-DA1）&quot;">​</a></h3><p>新しい KDS / レジ / ハンディタブレットを設置する時、手動でユーザー名・パスワードを入力する代わりに <strong>ワンタイムトークン</strong>で自動ログインできます（2026-04-18 追加）。</p><h4 id="手順-1" tabindex="-1">手順 <a class="header-anchor" href="#手順-1" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>dashboard.html → 【スタッフ管理】 → デバイスアカウントセクション</li><li><strong>【トークン発行】</strong> ボタン（<code>btn-token-device</code>、<code>dashboard.html</code> L303）</li><li>ダイアログで端末の「表示名」と「用途（visible_tools）」を入力</li><li><code>api/store/device-registration-token.php</code> がワンタイムトークンを発行し、セットアップ URL（<code>/public/admin/device-setup.html?token=...</code>）が表示される</li><li><strong>URL を新しい端末で開く</strong>（手動コピー、または QR にして読み取り）</li><li><code>device-setup.html</code> がページロード時に <code>POST /api/auth/device-register.php</code> を自動実行</li><li>サーバー側でトークンを検証し、<strong>device ロールのユーザーを新規作成</strong>（ユーザー名 <code>device_xxxxxxxxxxxx</code>、ランダムパスワード）</li><li>セッション Cookie がセットされ、<code>visible_tools</code> の優先度（<code>handy</code> &gt; <code>register</code> &gt; <code>kds</code>）に従って対応画面へ 3 秒後に自動遷移</li></ol><h4 id="セキュリティ制御-api-auth-device-register-php" tabindex="-1">セキュリティ制御（<code>api/auth/device-register.php</code>） <a class="header-anchor" href="#セキュリティ制御-api-auth-device-register-php" aria-label="Permalink to &quot;セキュリティ制御（`api/auth/device-register.php`）&quot;">​</a></h4><ul><li>ワンタイムトークン（<code>is_used=1</code> で 1 回限り有効）</li><li>有効期限短め（発行から <code>expires_hours</code> 時間）</li><li>レートリミット: 同一 IP から 1 時間 3 回まで</li><li><code>SELECT ... FOR UPDATE</code> でレース条件防止、tenant / store の <code>is_active=1</code> チェック</li><li>パスワードは <code>password_hash()</code> ハッシュのみ保存（平文は破棄）</li><li>成功時に <code>audit_log</code> に <code>event=&#39;device:register&#39;</code> を記録</li></ul><h3 id="_2-4-5-スタッフアカウントとの違い" tabindex="-1">2-4-5. スタッフアカウントとの違い <a class="header-anchor" href="#_2-4-5-スタッフアカウントとの違い" aria-label="Permalink to &quot;2-4-5. スタッフアカウントとの違い&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>staff</th><th>device</th></tr></thead><tbody><tr><td>想定用途</td><td>人間 1 人</td><td>端末 1 台</td></tr><tr><td>シフト管理対象</td><td>✅</td><td>❌</td></tr><tr><td>人件費計算対象</td><td>✅</td><td>❌</td></tr><tr><td>スタッフ評価レポート</td><td>✅</td><td>❌</td></tr><tr><td>GPS 打刻必須</td><td><code>gps_required</code> 設定次第</td><td><strong>常に必須</strong>（セキュリティ）</td></tr><tr><td>管理画面アクセス</td><td>限定（予約・シフト 2 タブのみ）</td><td>✗ 不可</td></tr></tbody></table><hr><h2 id="_2-5-シフトの作成と公開" tabindex="-1">2-5. シフトの作成と公開 <a class="header-anchor" href="#_2-5-シフトの作成と公開" aria-label="Permalink to &quot;2-5. シフトの作成と公開&quot;">​</a></h2><p>シフトの作成は <strong>「シフト管理」タブ</strong> から行います（manager 以上）。</p><h3 id="_2-5-1-シフトを作る手順" tabindex="-1">2-5-1. シフトを作る手順 <a class="header-anchor" href="#_2-5-1-シフトを作る手順" aria-label="Permalink to &quot;2-5-1. シフトを作る手順&quot;">​</a></h3><ol><li>dashboard.html → 上部タブ <strong>【シフト管理】</strong></li><li>サブタブ <strong>【週間カレンダー】</strong>（<code>data-tab=&quot;shift-calendar&quot;</code>）</li><li>画面上部の日付切替ボタンで該当週を表示</li><li>スタッフ名 × 日付のグリッドが表示される</li><li>セル（スタッフ × 日）をタップ</li><li>シフト入力モーダル:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>開始時刻</strong></td><td>例: <code>10:00</code></td></tr><tr><td><strong>終了時刻</strong></td><td>例: <code>18:00</code></td></tr><tr><td><strong>ポジション</strong></td><td>ホール / キッチン / レジ / 清掃 等（カスタマイズ可）</td></tr><tr><td><strong>メモ</strong></td><td>任意（例: 「研修日」）</td></tr></tbody></table><ol start="7"><li><strong>【保存】</strong></li><li>セルに色付きでシフトが表示される</li></ol><h3 id="_2-5-2-全員分入力できたら公開" tabindex="-1">2-5-2. 全員分入力できたら公開 <a class="header-anchor" href="#_2-5-2-全員分入力できたら公開" aria-label="Permalink to &quot;2-5-2. 全員分入力できたら公開&quot;">​</a></h3><ol><li>画面上部の <strong>【週間公開】</strong> ボタン</li><li>確認ダイアログ → <strong>【OK】</strong></li><li>スタッフ全員に通知される（「マイシフト」で閲覧可能）</li><li>以降、スタッフは自分のシフトを確認できる</li></ol><h3 id="_2-5-3-ai-シフト提案を使う" tabindex="-1">2-5-3. AI シフト提案を使う <a class="header-anchor" href="#_2-5-3-ai-シフト提案を使う" aria-label="Permalink to &quot;2-5-3. AI シフト提案を使う&quot;">​</a></h3><p>過去の売上データとスタッフの希望から、最適なシフトを AI が自動生成する機能。</p><ol><li>カレンダー画面上部の <strong>【🤖 AI 提案】</strong> ボタン</li><li>AI が数秒で全スタッフのシフト案を生成</li><li>内容を画面で確認</li><li><strong>【適用】</strong> ボタンで一括反映（既存の手動シフトは上書きされない）</li><li>確定したら <strong>【週間公開】</strong> で公開</li></ol><hr><h2 id="_2-6-出退勤の打刻方法と確認" tabindex="-1">2-6. 出退勤の打刻方法と確認 <a class="header-anchor" href="#_2-6-出退勤の打刻方法と確認" aria-label="Permalink to &quot;2-6. 出退勤の打刻方法と確認&quot;">​</a></h2><h3 id="_2-6-1-スタッフの打刻" tabindex="-1">2-6-1. スタッフの打刻 <a class="header-anchor" href="#_2-6-1-スタッフの打刻" aria-label="Permalink to &quot;2-6-1. スタッフの打刻&quot;">​</a></h3><p>スタッフ側の操作。</p><ol><li>管理画面（<code>https://eat.posla.jp/public/admin/</code>）に staff アカウントでログイン</li><li>デフォルト表示される「スタッフ画面」の <strong>【🟢 出勤】</strong> ボタン（緑、2026-04-19 ヘッダーから移動）をタップ</li><li><strong>GPS 許可ダイアログ</strong> が出たら <strong>【許可】</strong></li><li>店舗から半径 200m 以内（デフォルト）にいるか判定</li><li>OK なら <strong>「出勤しました 10:05」</strong> とメッセージ</li><li>退勤時は <strong>【退勤】</strong> ボタン（赤）をタップ</li></ol><h3 id="_2-6-2-店長の勤怠確認" tabindex="-1">2-6-2. 店長の勤怠確認 <a class="header-anchor" href="#_2-6-2-店長の勤怠確認" aria-label="Permalink to &quot;2-6-2. 店長の勤怠確認&quot;">​</a></h3><ol><li>dashboard.html → 【シフト管理】 → サブタブ <strong>【勤怠一覧】</strong>（<code>data-tab=&quot;shift-attendance&quot;</code>）</li><li>日別にスタッフの打刻記録が一覧表示</li><li>予定（シフト）vs 実績（打刻）の比較</li><li>遅刻・早退・残業が自動計算</li><li>打刻漏れがある場合は <strong>【編集】</strong> で手動修正</li></ol><hr><h2 id="_2-7-gps-打刻の設定" tabindex="-1">2-7. GPS 打刻の設定 <a class="header-anchor" href="#_2-7-gps-打刻の設定" aria-label="Permalink to &quot;2-7. GPS 打刻の設定&quot;">​</a></h2><h3 id="_2-7-1-店舗の-gps-設定" tabindex="-1">2-7-1. 店舗の GPS 設定 <a class="header-anchor" href="#_2-7-1-店舗の-gps-設定" aria-label="Permalink to &quot;2-7-1. 店舗の GPS 設定&quot;">​</a></h3><ol><li>dashboard.html → 【シフト管理】 → <strong>【シフト設定】</strong> サブタブ（<code>data-tab=&quot;shift-settings&quot;</code>）</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>店舗緯度</strong></td><td>Google Maps で店舗の住所を検索 → 右クリック → 座標をコピー（例: 35.6585）</td></tr><tr><td><strong>店舗経度</strong></td><td>同上（例: 139.7454）</td></tr><tr><td><strong>GPS 許容半径</strong></td><td>デフォルト 200m（実装: <code>sql/schema.sql</code> L871 <code>gps_radius_meters DEFAULT 200</code>）</td></tr><tr><td><strong>GPS 打刻必須</strong></td><td>トグル ON/OFF（デフォルト OFF、<code>gps_required</code> カラム）</td></tr></tbody></table><ol start="3"><li><strong>【保存】</strong></li></ol><h3 id="_2-7-2-店舗座標の調べ方-google-maps" tabindex="-1">2-7-2. 店舗座標の調べ方（Google Maps） <a class="header-anchor" href="#_2-7-2-店舗座標の調べ方-google-maps" aria-label="Permalink to &quot;2-7-2. 店舗座標の調べ方（Google Maps）&quot;">​</a></h3><ol><li><a href="https://www.google.com/maps" target="_blank" rel="noreferrer">Google Maps</a> を開く</li><li>店舗の住所を検索</li><li>地図上の店舗アイコンを右クリック</li><li><strong>「座標をコピー」</strong> または表示された緯度経度の数字をメモ</li><li>例: <code>35.6585, 139.7454</code> → 緯度 35.6585 / 経度 139.7454</li></ol><h3 id="_2-7-3-device-ロールは常に-gps-必須" tabindex="-1">2-7-3. device ロールは常に GPS 必須 <a class="header-anchor" href="#_2-7-3-device-ロールは常に-gps-必須" aria-label="Permalink to &quot;2-7-3. device ロールは常に GPS 必須&quot;">​</a></h3><p>スタッフ（staff ロール）は <code>gps_required</code> 設定次第で GPS 打刻の必須/任意が変わりますが、<strong>device ロールは設定関係なく常に GPS 必須</strong>（<code>public/handy/js/handy-app.js</code> L1647-1648）。理由: device 端末は店舗備品なので、店舗外に持ち出されたらセキュリティリスクが高いため。</p><h3 id="_2-7-4-gps-がずれる場合" tabindex="-1">2-7-4. GPS がずれる場合 <a class="header-anchor" href="#_2-7-4-gps-がずれる場合" aria-label="Permalink to &quot;2-7-4. GPS がずれる場合&quot;">​</a></h3><ul><li>室内だと GPS 精度が落ちる（5〜50m ずれることも）</li><li>ビル内の店舗は特に誤差が大きい</li><li>対処: 許容半径を <strong>300〜500m</strong> に広げる</li><li>それでもダメなら <strong>GPS 必須を OFF</strong> にして、代わりに監査ログで出退勤を確認</li></ul><hr><h2 id="_2-8-ai-シフト提案の詳細" tabindex="-1">2-8. AI シフト提案の詳細 <a class="header-anchor" href="#_2-8-ai-シフト提案の詳細" aria-label="Permalink to &quot;2-8. AI シフト提案の詳細&quot;">​</a></h2><h3 id="_2-8-1-仕組み" tabindex="-1">2-8-1. 仕組み <a class="header-anchor" href="#_2-8-1-仕組み" aria-label="Permalink to &quot;2-8-1. 仕組み&quot;">​</a></h3><ul><li>過去 30〜90 日の売上データ分析</li><li>各時間帯の必要人員を推定</li><li>スタッフごとの希望シフト（シフト希望提出機能）との合致</li><li>労基法遵守（週40時間以下、1日8時間以下）</li></ul><h3 id="_2-8-2-使い方" tabindex="-1">2-8-2. 使い方 <a class="header-anchor" href="#_2-8-2-使い方" aria-label="Permalink to &quot;2-8-2. 使い方&quot;">​</a></h3><ol><li>シフト希望を集める（スタッフが 【希望提出】 サブタブで送信）</li><li>【週間カレンダー】で <strong>【🤖 AI 提案】</strong> ボタン</li><li>提案内容を確認</li><li>修正が必要なら手動調整</li><li><strong>【週間公開】</strong> で確定</li></ol><h3 id="_2-8-3-注意点" tabindex="-1">2-8-3. 注意点 <a class="header-anchor" href="#_2-8-3-注意点" aria-label="Permalink to &quot;2-8-3. 注意点&quot;">​</a></h3><ul><li>AI 提案は「あくまで案」。最終判断はマネージャー</li><li>新人スタッフの研修シフト等、AI には見えない要素は手動調整</li><li>既存の手動シフトは上書きされない（note=&#39;AI提案&#39; のものだけ上書き）</li></ul><hr><h2 id="_2-9-複数店舗のシフトヘルプ" tabindex="-1">2-9. 複数店舗のシフトヘルプ <a class="header-anchor" href="#_2-9-複数店舗のシフトヘルプ" aria-label="Permalink to &quot;2-9. 複数店舗のシフトヘルプ&quot;">​</a></h2><p>owner / manager のみが使える機能。他店舗から人員を借りる仕組み。</p><h3 id="_2-9-1-ヘルプ要請を送る" tabindex="-1">2-9-1. ヘルプ要請を送る <a class="header-anchor" href="#_2-9-1-ヘルプ要請を送る" aria-label="Permalink to &quot;2-9-1. ヘルプ要請を送る&quot;">​</a></h3><ol><li>dashboard.html → 【シフト管理】 → <strong>【ヘルプ】</strong> サブタブ（<code>data-tab=&quot;shift-help&quot;</code>、<code>shift_help_requests</code> 機能）</li><li><strong>【+ ヘルプ要請】</strong> ボタン</li><li>入力: <ul><li>送信先店舗（同テナント内の他店舗から選択）</li><li>希望日時</li><li>ポジション（ホール / キッチン等）</li><li>必要人数</li><li>理由・メモ</li></ul></li><li><strong>【送信】</strong></li><li>相手店舗のマネージャーに通知される</li></ol><h3 id="_2-9-2-ヘルプ要請を受ける-承認する" tabindex="-1">2-9-2. ヘルプ要請を受ける / 承認する <a class="header-anchor" href="#_2-9-2-ヘルプ要請を受ける-承認する" aria-label="Permalink to &quot;2-9-2. ヘルプ要請を受ける / 承認する&quot;">​</a></h3><ol><li>相手店舗のマネージャーが【ヘルプ】サブタブで要請を確認</li><li>承認できる場合 → スタッフを選択 → <strong>【承認】</strong></li><li>選ばれたスタッフは要請元の店舗で勤務できるようになる（その日だけ）</li></ol><h3 id="_2-9-3-スタッフが他店舗で働く" tabindex="-1">2-9-3. スタッフが他店舗で働く <a class="header-anchor" href="#_2-9-3-スタッフが他店舗で働く" aria-label="Permalink to &quot;2-9-3. スタッフが他店舗で働く&quot;">​</a></h3><ol><li>スタッフがハンディ画面でログイン</li><li>所属店舗切替で派遣先店舗を選択</li><li>その日は派遣先店舗のシフトで稼働</li></ol><hr><h2 id="_2-10-シフト希望の提出-スタッフ側" tabindex="-1">2-10. シフト希望の提出（スタッフ側） <a class="header-anchor" href="#_2-10-シフト希望の提出-スタッフ側" aria-label="Permalink to &quot;2-10. シフト希望の提出（スタッフ側）&quot;">​</a></h2><p>スタッフが自分の希望シフトを提出する機能。</p><h3 id="手順-2" tabindex="-1">手順 <a class="header-anchor" href="#手順-2" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>スタッフが dashboard.html にログイン</li><li>【シフト管理】 → サブタブ <strong>【希望提出】</strong>（<code>data-tab=&quot;shift-availability&quot;</code>、staff 専用）</li><li>カレンダー表示</li><li>希望日をタップ → 時間帯入力（例: 10:00〜15:00 希望）</li><li><strong>【保存】</strong></li><li>マネージャーがシフト作成時に参考にする</li></ol><hr><h2 id="_2-11-シフト集計-労働時間・人件費" tabindex="-1">2-11. シフト集計（労働時間・人件費） <a class="header-anchor" href="#_2-11-シフト集計-労働時間・人件費" aria-label="Permalink to &quot;2-11. シフト集計（労働時間・人件費）&quot;">​</a></h2><h3 id="手順-3" tabindex="-1">手順 <a class="header-anchor" href="#手順-3" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>【シフト管理】 → サブタブ <strong>【集計サマリー】</strong>（<code>data-tab=&quot;shift-summary&quot;</code>、manager 以上）</li><li>期間を指定（日次 / 週次 / 月次）</li><li>以下が表示:</li></ol><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>総労働時間</td><td>全スタッフの合計実働時間</td></tr><tr><td>人件費</td><td><code>hourly_rate × 実働時間</code> の合計</td></tr><tr><td>スタッフ別労働時間</td><td>個別の実働時間</td></tr><tr><td>労基法警告</td><td>週 40 時間超過、月 80 時間残業等があればアラート</td></tr><tr><td>深夜労働時間</td><td>22:00〜05:00 の時間（深夜割増対象）</td></tr></tbody></table><hr><h2 id="_2-12-スタッフ向けマイシフト閲覧" tabindex="-1">2-12. スタッフ向けマイシフト閲覧 <a class="header-anchor" href="#_2-12-スタッフ向けマイシフト閲覧" aria-label="Permalink to &quot;2-12. スタッフ向けマイシフト閲覧&quot;">​</a></h2><p>スタッフが自分の確定シフトを見る機能。</p><ol><li>スタッフが dashboard.html にログイン</li><li>【シフト管理】 → サブタブ <strong>【マイシフト】</strong>（<code>data-tab=&quot;shift-my&quot;</code>、staff 専用）</li><li>自分のシフトだけがカレンダーで見える</li><li>他のスタッフのシフトは見えない</li></ol><hr><h2 id="_2-13-よくある質問" tabindex="-1">2-13. よくある質問 <a class="header-anchor" href="#_2-13-よくある質問" aria-label="Permalink to &quot;2-13. よくある質問&quot;">​</a></h2><p><strong>Q1. 既存のスタッフアカウントを KDS タブレットでログインしっぱなしにしてはダメ？</strong></p><p>A1. <strong>強く非推奨</strong>。シフト・勤怠・スタッフ評価レポートが全部そのスタッフ名義になってしまい、データが壊れます。必ず device アカウントを作って運用してください。</p><p><strong>Q2. device アカウントは何個まで作れる？</strong></p><p>A2. 上限なし。店舗の KDS 台数 + レジ台数 + ハンディ台数分作ってください。例: 3 店舗 × 各 KDS 2 台・レジ 1 台・ハンディ 3 台 = 18 個。</p><p><strong>Q3. device アカウントはシフト管理に影響しない？</strong></p><p>A3. 影響しません。<code>role=&#39;device&#39;</code> のユーザーはシフト・勤怠・人件費・スタッフ評価の SQL クエリから完全に除外されます。</p><p><strong>Q4. 退職したスタッフのアカウント、削除すべき？</strong></p><p>A4. 無効化推奨（トグル OFF）。過去の勤怠・注文履歴を守るため。完全削除は非推奨。</p><p><strong>Q5. GPS 打刻の精度が悪い</strong></p><p>A5. 室内では GPS が 5〜50m ずれることがあります。許容半径を 300〜500m に広げるか、GPS 必須を OFF にして監査ログで確認してください。</p><p><strong>Q6. スタッフが勤怠打刻を忘れた</strong></p><p>A6. マネージャーが【勤怠一覧】の該当日を <strong>【編集】</strong> で手動追加できます。ただし監査ログには「編集されたシフト」と記録されます。</p><p><strong>Q7. AI シフト提案の質が悪い</strong></p><p>A7. 過去データの蓄積が少ないと AI 精度が低くなります。最低 30 日分のデータが溜まってから使うのが現実的です。</p><hr><h2 id="_2-14-付録-ロール作成権限マトリクス" tabindex="-1">2-14. 付録: ロール作成権限マトリクス <a class="header-anchor" href="#_2-14-付録-ロール作成権限マトリクス" aria-label="Permalink to &quot;2-14. 付録: ロール作成権限マトリクス&quot;">​</a></h2><p>実装: <code>api/owner/users.php</code> L113 + <code>api/store/staff-management.php</code> L42</p><table tabindex="0"><thead><tr><th>作成者 \\ 作成対象</th><th>owner</th><th>manager</th><th>staff</th><th>device</th></tr></thead><tbody><tr><td><strong>owner</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>manager</strong></td><td>❌</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td><strong>staff</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><hr><h2 id="_2-15-次のページへ" tabindex="-1">2-15. 次のページへ <a class="header-anchor" href="#_2-15-次のページへ" aria-label="Permalink to &quot;2-15. 次のページへ&quot;">​</a></h2><p>→ <a href="./part3-menu.html">Part 3: メニュー管理</a></p>',160)])])}const u=o(e,[["render",l]]);export{b as __pageData,u as default};
